// Strategy אמיתי מ-ATP2021_Lab3
public interface IWorkerComparator {
    int compare(Worker w1, Worker w2);
}

public class WorkerAgeComparator implements IWorkerComparator {
    public int compare(Worker w1, Worker w2) { return w1.getAge() - w2.getAge(); }
}

public abstract class ACommonWorkerSorter implements IWorkerSorter {
    protected IWorkerComparator workerComparator; // ה-Strategy מוזרקת ב-Composition
    public ACommonWorkerSorter(IWorkerComparator workerComparator) {
        this.workerComparator = workerComparator;
    }
}

public class BubbleWorkerSorter extends ACommonWorkerSorter {
    public BubbleWorkerSorter(IWorkerComparator workerComparator) { super(workerComparator); }
    @Override
    public void sort(Worker[] workers) {
        boolean swapped = true;
        while (swapped) {
            swapped = false;
            for (int i = 1; i < workers.length; i++) {
                if (workerComparator.compare(workers[i - 1], workers[i]) > 0) {
                    Worker temp = workers[i - 1];
                    workers[i - 1] = workers[i];
                    workers[i] = temp;
                    swapped = true;
                }
            }
        }
    }
}

// שימוש - אותו אלגוריתם מיון, שלוש אסטרטגיות שונות:
