// Adapter: התאמת Runnable לממשק Callable
class RunnableToCallableAdapter implements Callable<Object> {
    private final Runnable runnable;
    RunnableToCallableAdapter(Runnable r) { this.runnable = r; }
    public Object call() {
        runnable.run();
        return null;
    }
}

